from flask import Flask, request, jsonify
import pickle
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
EXPIRATION_TIME = 3600  # Cache expires after 1 hour

if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def get_cache_key(url, params):
    return f"{url}_{hash(str(params))}"

def load_from_cache(key):
    cache_file = os.path.join(CACHE_DIR, key)
    if os.path.exists(cache_file) and time.time() - os.path.getmtime(cache_file) < EXPIRATION_TIME:
        with open(cache_file, 'rb') as f:
            return pickle.load(f)
    return None

def save_to_cache(key, data):
    cache_file = os.path.join(CACHE_DIR, key)
    with open(cache_file, 'wb') as f:
        pickle.dump(data, f)

@app.route('/api', methods=['GET'])
def api():
    url = request.url
    params = request.args.to_dict()
    key = get_cache_key(url, params)
    
    cached_data = load_from_cache(key)
    if cached_data is not None:
        return jsonify(cached_data), 200
    
    # Simulate an expensive API call
    response_data = {
        'data': {
            'items': [1, 2, 3],
            'metadata': {'timestamp': time.time()}
        }
    }
    
    save_to_cache(key, response_data)
    return jsonify(response_data), 200

if __name__ == '__main__':
    app.run(debug=True)